    function drawBushes(now){ if(!royBushes.length) return; ctx.save(); var _bf=(typeof NS_BUSH!=='undefined'&&NS_BUSH.length); for(var _b=0;_b<royBushes.length;_b++){ var p=royBushes[_b], r=p.r; if(p.rust>0){ p.rust-=0.045; if(p.rust<0)p.rust=0; } var _rustling=p.rust>0.02; var _ballIn=(typeof coin!=='undefined'&&coin)?(Math.hypot(coin.x-p.x,coin.y-p.y)<p.r+COIN_R):false; ctx.globalAlpha=0.20; ctx.fillStyle='#000'; ctx.beginPath(); ctx.ellipse(p.x,p.y+r*0.5,r*0.85,r*0.32,0,0,6.283); ctx.fill(); ctx.globalAlpha=1; var _jit=_rustling?Math.sin(now*0.06+_b*2)*3.6*Math.min(1.5,p.rust):0; var _im=_bf?NS_BUSH[(p.rust>0.5)?(Math.floor(now/60)%NS_BUSH.length):1]:null; ctx.globalAlpha=_ballIn?0.68:1; if(_im&&_im.complete&&_im.naturalWidth){ var _sz=r*1.9; ctx.drawImage(_im, Math.round(p.x-_sz/2+_jit), Math.round(p.y-_sz*0.58), _sz, _sz); } else { var lobes=[[0,0,r],[-r*0.55,r*0.12,r*0.6],[r*0.55,r*0.06,r*0.6],[0,-r*0.5,r*0.55]]; ctx.fillStyle='#345c24'; for(var i=0;i<lobes.length;i++){ ctx.beginPath(); ctx.arc(p.x+lobes[i][0]+_jit,p.y+lobes[i][1],lobes[i][2],0,6.283); ctx.fill(); } ctx.fillStyle='#528a3a'; for(var i2=0;i2<lobes.length;i2++){ ctx.beginPath(); ctx.arc(p.x+lobes[i2][0]-1+_jit,p.y+lobes[i2][1]-1.5,lobes[i2][2]*0.62,0,6.283); ctx.fill(); } } } ctx.restore(); }
