    function royCactiStep(){ if(!royCacti.length||!moving||scoring||current==='blue') return; if((typeof ghosting!=='undefined'&&ghosting)||(typeof TAC!=='undefined'&&TAC&&TAC.ghost&&typeof ghostUsed!=='undefined'&&!ghostUsed)) return; for(var _c=0;_c<royCacti.length;_c++){ var p=royCacti[_c]; var dx=coin.x-p.x, dy=coin.y-p.y, d=Math.hypot(dx,dy), R=p.r+COIN_R; if(d<R && d>0.001){ var nx=dx/d, ny=dy/d, vn=coin.vx*nx+coin.vy*ny; if(vn<0){ coin.vx-=2*vn*nx; coin.vy-=2*vn*ny; } coin.x=p.x+nx*R; coin.y=p.y+ny*R; coin.vx*=0.66; coin.vy*=0.66; p.hit=1; try{ spawnSparks(p.x+nx*p.r,p.y+ny*p.r,'#cfe08a',6); }catch(e){} try{ if(typeof haptic==='function') haptic(18); }catch(e){} try{ if(!muted){ if(typeof sfxWall==='function') sfxWall(); else if(typeof sfxCurl==='function') sfxCurl(); } }catch(e){} break; } } }
