    function rollGeysers(){ if(royGeyserArena()){ if(!royGeysers.length && !moving){ for(var _gg=0;_gg<2;_gg++){ var gx,gy,ok=false,tries=0,gr=13; while(!ok&&tries<80){ tries++; gx=WALL+18+Math.random()*(W-2*WALL-36); gy=NET_DEPTH+GOAL_AREA_D+20+Math.random()*(H-2*(NET_DEPTH+GOAL_AREA_D)-40); if(Math.abs(gx-W/2)<GOAL_W*0.5 && (gy<NET_DEPTH+GOAL_AREA_D+28||gy>H-NET_DEPTH-GOAL_AREA_D-28)) continue; if(_sandBlocked(gx,gy,gr)) continue; ok=true; } if(ok) royGeysers.push({x:gx,y:gy,r:gr,period:150+Math.floor(Math.random()*70),t:Math.floor(Math.random()*150),erupt:false,fired:false}); } } } else if(royGeysers.length){ royGeysers=[]; } }
