    function drawGeysers(now){ if(!royGeysers.length) return; ctx.save(); for(var _g=0;_g<royGeysers.length;_g++){ var p=royGeysers[_g], r=p.r; ctx.globalAlpha=0.9; ctx.fillStyle='#7a5a30'; ctx.beginPath(); ctx.ellipse(p.x,p.y,r*0.85,r*0.5,0,0,6.283); ctx.fill(); ctx.fillStyle='#5a3f1e'; ctx.beginPath(); ctx.ellipse(p.x,p.y,r*0.5,r*0.28,0,0,6.283); ctx.fill(); ctx.globalAlpha=1; if(p.erupt){ var _e=1-(p.t/26); for(var _k=0;_k<14;_k++){ var _pt=(_k/14), _rise=(_pt+ (now*0.02)%1)%1; var _px=p.x+Math.sin(_k*2.1+now*0.02)*r*0.5*(1-_rise), _py=p.y-_rise*r*3.0*_e, _pr=1+ (1-_rise)*1.8; ctx.globalAlpha=(1-_rise)*0.85*_e; ctx.fillStyle=_k%2?'#f2ddab':'#d9bd82'; ctx.beginPath(); ctx.arc(_px,_py,_pr,0,6.283); ctx.fill(); } ctx.globalAlpha=1; } } ctx.restore(); }
