    function royDevilTick(dt){ if(!royDevil||royDevil.hasBall) return; var _st=dt/16.67; if(_st>3)_st=3; if(_st<0.2)_st=0.2; var s=royDevil; s.phase+=0.18*_st*s.spin; var dx=s.tx-s.x, dy=s.ty-s.y, d=Math.hypot(dx,dy)||1; if(d<6){ _devilRetarget(); } else { var sp=0.75*_st; s.x+=(dx/d)*sp; s.y+=(dy/d)*sp; } }
